import React, { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { useJournalEntryFormState } from '../../features/kt/journal-entry/shared/hooks/useJournalEntryFormState';
import { useLocation } from 'react-router-dom';
import { useInAppNavigate } from '../../router/useInAppNavigate';
import {
  Button, Checkbox, Input, LabelMoney, Modal, MoneyInput, Select, dispatchAppToast,
  utcToLocalInputValue, localInputToISOWithOffset,
} from '@linm-soft-org/linm-web-common-components';
import { useAppDispatch } from '../../store/hooks';
import { ktService } from '../../services/kt/ktService';
import type {
  CashVoucherDto,
  CreateJournalEntryDto,
  DocumentPostingStatus,
  JournalEntryDto,
} from '../../services/kt/models';
import { pollDocumentPostingStatus } from '../../utils/pollDocumentPostingStatus';
import { AccountSearchInput, ContractSearchField, useAccountSearchAsOfDate } from '../search';
import { erpFinanceAccountSearchApi, formatAccountDisplay } from '../search/accountSearchApi';
import { salesService } from '../../services/sales/salesService';
import { getApiErrorMessage } from '../../utils/getApiErrorMessage';
import { ValidationErrorBanner } from '../layout';
import {
  VoucherDescriptionField,
  VoucherFormToolbar,
  VoucherFormStatusGroup,
  ProcessingLevelApproveModal,
  VoucherSearchSlideout,
  VoucherPrintModal,
  VoucherPostedLedgerModal,
  useVoucherFormRoute,
  buildVoucherCopyNavigateState,
  buildVoucherSearchNavigateState,
  VOUCHER_SEARCH_CACHE_MAX,
} from '../voucher';
import { formatProcessingLevelFromOptions } from '../../utils/voucherProcessingLevelOptions';
import { JOURNAL_ENTRY_PHIEU_DIEU_CHINH_CONFIG, type JournalEntryPageConfig } from '../../constants/journalEntryPageConfig';
import {
  FormMode,
  UnsavedChangesModal,
  effectiveFormMode,
  fieldPlaceholder,
  initialFormMode,
  isEditingMode,
  isViewMode,
  shouldStartFormInEditMode,
  withFormEditModeSearch,
  withoutFormEditModeSearch,
  useFormFieldLock,
  useTopbarAutoHideOnScroll,
  useVoucherFormShellHeight,
  useFormEmbedSlideout,
  useFormRouteId,
} from '../form';
import type { FormNavigateEditIntent } from '../form';
import { useUnsavedChangesGuard } from '../../hooks/useUnsavedChangesGuard';
import { useLinesGridMessageTitles } from '../../hooks/useLinesGridMessageTitles';
import { useSelectedLineRowSync } from '../../hooks/useSelectedLineRowSync';
import { useVoucherInitData } from '../../hooks/useVoucherInitData';
import { resolveProcessingLevelSelectOptions } from '../../utils/voucherProcessingLevelOptions';
import {
  buildVoucherToolbarDisabledReasons,
  isVoucherFormFieldLocked,
  isVoucherFormStatusLocked,
  resolveVoucherViewModeHint,
} from '../../utils/voucherProcessingLevelDisplay';
import { resolveVoucherFormToolbarFlags } from '../../utils/resolveVoucherFormToolbarFlags';
import {
  voucherApproveDisabledReason,
} from '../../utils/voucherToolbarActions';
import { journalEntryToSearchRow } from '../../utils/journalEntrySearchRow';
import { validateVoucherDateAgainstPeriods } from '../../utils/accountingPeriodDateValidation';
import type { AccountingPeriodGate } from '../../utils/voucherToolbarActions';
import {
  collectJournalEntryBannerMessages,
  insertJournalEntryLineFieldErrors,
  scrollToFirstJournalEntryFieldError,
  shiftJournalEntryLineFieldErrors,
  validateJournalEntryFields,
  type JournalEntryFieldErrors,
} from '../../utils/journalEntryFieldValidation';
import { applyInlineValidationMessage } from '../../utils/voucherFieldValidation';
import df from '../../styles/documentForm.module.css';

export interface JournalEntryFormProps {
  config?: JournalEntryPageConfig;
}

interface LineRow {
  debitAccountCode: string;
  debitAccountName: string;
  creditAccountCode: string;
  creditAccountName: string;
  amount: number;
  description: string;
}

const emptyLine = (): LineRow => ({
  debitAccountCode: '',
  debitAccountName: '',
  creditAccountCode: '',
  creditAccountName: '',
  amount: 0,
  description: '',
});

type JournalEntrySnapshot = {
  entryDate: string;
  code: string;
  description: string;
  referenceNo: string;
  referenceCustomerName: string;
  processingLevel: string;
  entryType?: string;
  autoReverse?: boolean;
  lines: LineRow[];
};

function serializeJournalSnapshot(input: JournalEntrySnapshot): string {
  return JSON.stringify(input);
}

/** Clicks/keys on lookup inputs must not move focus to `<tr>` — breaks SearchInput dropdown. */
function isLineRowFieldTarget(target: HTMLElement): boolean {
  return !!target.closest(
    'input, textarea, select, button, a, [role="option"], [role="listbox"]',
  );
}

export const JournalEntryForm: React.FC<JournalEntryFormProps> = ({ config = JOURNAL_ENTRY_PHIEU_DIEU_CHINH_CONFIG }) => {
  const id = useFormRouteId();
  const isNew = !id;
  const navigate = useInAppNavigate();
  const location = useLocation();
  const dispatch = useAppDispatch();
  const startInEditMode = !isNew && shouldStartFormInEditMode(
    location.search,
    location.state as FormNavigateEditIntent | null,
  );
  const tid = (suffix: string) => `${config.testIdPrefix}-${suffix}`;
  const showContractRef = config.entryKind === 'General';
  const showPktFields = config.entryKind === 'Adjusting';
  const descriptionSpanClass = showContractRef ? df.spanCol3 : df.spanCol4;
  const validationBannerId = tid('validation-banner');

  const {
    entryDate,
    setEntryDate,
    code,
    setCode,
    description,
    setDescription,
    referenceNo,
    setReferenceNo,
    referenceCustomerName,
    setReferenceCustomerName,
    status,
    setStatus,
    lines,
    lineRows,
    setLines,
    updateLine,
    insertLineAfter,
    removeLine,
    applyFormState,
    processingLevel,
    setProcessingLevel,
    formMode,
    setFormMode,
  } = useJournalEntryFormState(initialFormMode(isNew, { startInEditMode }));

  const accountSearchOptions = useAccountSearchAsOfDate(entryDate);

  const initFormName = isNew ? config.initDataCreateFormName : config.initDataEditFormName;
  const { processingLevelOptions, defaultProcessingLevel, journalEntryTypeOptions, formPermissions, initError, loading: initLoading } = useVoucherInitData(initFormName);
  const [entryType, setEntryType] = useState('Standard');
  const [autoReverse, setAutoReverse] = useState(false);
  const processingOpts = React.useMemo(
    () => resolveProcessingLevelSelectOptions(processingLevelOptions, defaultProcessingLevel),
    [processingLevelOptions, defaultProcessingLevel],
  );
  const resolvedProcessingLevel = processingLevel || defaultProcessingLevel || '';

  const [loading, setLoading] = useState(false);
  const [saving, setSaving] = useState(false);
  const [accountingPeriods, setAccountingPeriods] = useState<AccountingPeriodGate[]>([]);
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [showApproveModal, setShowApproveModal] = useState(false);
  const [showSearchSlideout, setShowSearchSlideout] = useState(false);
  const [showPrintModal, setShowPrintModal] = useState(false);
  const [showLedgerModal, setShowLedgerModal] = useState(false);
  const [printing, setPrinting] = useState(false);
  const [approving, setApproving] = useState(false);
  const [postingStatus, setPostingStatus] = useState<DocumentPostingStatus>('None');
  const [searchResultIds, setSearchResultIds] = useState<string[]>([]);
  const searchCacheRef = useRef(new Map<string, JournalEntryDto>());
  const searchListItemsRef = useRef<JournalEntryDto[]>([]);
  /** Pattern B — inline errors only after first Lưu attempt. */
  const validationAttemptedRef = useRef(false);
  const [fieldErrors, setFieldErrors] = useState<JournalEntryFieldErrors>({});
  const [validationErrors, setValidationErrors] = useState<string[]>([]);
  const [bannerExpanded, setBannerExpanded] = useState(true);
  const [bannerClosed, setBannerClosed] = useState(false);
  const [savedSnapshot, setSavedSnapshot] = useState<string | null>(null);
  const newFormBaselineReady = useRef(false);
  const editIntentAppliedForIdRef = useRef<string | null>(null);
  const shellRef = useRef<HTMLDivElement>(null);
  const scrollRef = useRef<HTMLDivElement>(null);
  const linesSectionRef = useRef<HTMLDivElement>(null);
  const rowRefs = useRef<(HTMLTableRowElement | null)[]>([]);
  const [selectedLineIndex, setSelectedLineIndex] = useState(0);
  const embedSlideout = useFormEmbedSlideout();

  useVoucherFormShellHeight(shellRef, !embedSlideout);
  useTopbarAutoHideOnScroll(scrollRef, !embedSlideout);

  const syncEditModeInUrl = useCallback((nextMode: FormMode) => {
    if (isNew) return;
    const nextSearch = nextMode === FormMode.Edit
      ? withFormEditModeSearch(location.search)
      : withoutFormEditModeSearch(location.search);
    const routerState = location.state as FormNavigateEditIntent | null;
    const nextState = nextMode === FormMode.View && routerState?.startInEditMode
      ? (() => {
        const stripped = { ...(location.state as Record<string, unknown>) };
        delete stripped.startInEditMode;
        return stripped;
      })()
      : location.state;
    if (nextSearch === location.search && nextState === location.state) return;
    navigate(
      { pathname: location.pathname, search: nextSearch },
      { replace: true, state: nextState },
    );
  }, [isNew, location.pathname, location.search, location.state, navigate]);

  useEffect(() => {
    if (isNew) {
      editIntentAppliedForIdRef.current = null;
      return;
    }
    const hasEditIntent = shouldStartFormInEditMode(
      location.search,
      location.state as FormNavigateEditIntent | null,
    );
    if (!hasEditIntent) {
      if (editIntentAppliedForIdRef.current === id) {
        editIntentAppliedForIdRef.current = null;
      }
      return;
    }
    if (editIntentAppliedForIdRef.current === id) return;
    editIntentAppliedForIdRef.current = id ?? null;
    setFormMode(FormMode.Edit);
  }, [isNew, id, location.search, location.state, setFormMode]);

  useEffect(() => {
    if (selectedLineIndex >= lines.length) {
      setSelectedLineIndex(Math.max(0, lines.length - 1));
    }
  }, [lines.length, selectedLineIndex]);

  useEffect(() => {
    let cancelled = false;
    const t = setTimeout(() => {
      ktService.getPeriods()
        .then(periods => { if (!cancelled) setAccountingPeriods(periods); })
        .catch(() => { /* BE validates on save */ });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, []);

  useSelectedLineRowSync(rowRefs, selectedLineIndex, {
    sectionRef: linesSectionRef,
    isFieldTarget: isLineRowFieldTarget,
  });

  useLinesGridMessageTitles(linesSectionRef, [fieldErrors, lines.length]);

  useEffect(() => {
    const root = linesSectionRef.current;
    if (!root) return undefined;

    const onKeyDown = (e: KeyboardEvent) => {
      if (e.key !== 'ArrowUp' && e.key !== 'ArrowDown') return;
      const target = e.target as HTMLElement;
      if (isLineRowFieldTarget(target)) return;
      if (!root.contains(target)) return;

      e.preventDefault();
      if (e.key === 'ArrowDown') {
        setSelectedLineIndex(i => Math.min(i + 1, lines.length - 1));
      } else {
        setSelectedLineIndex(i => Math.max(i - 1, 0));
      }
    };

    root.addEventListener('keydown', onKeyDown);
    return () => root.removeEventListener('keydown', onKeyDown);
  }, [lines.length]);

  const toolbarMode = effectiveFormMode(isNew, formMode);
  const isViewReadOnly = isVoucherFormStatusLocked(status, processingLevel);
  const isFieldLocked = isVoucherFormFieldLocked(status, processingLevel, toolbarMode);
  const {
    isReadOnly,
    fieldLockProps,
    staticFieldProps,
    searchDisabled,
    searchViewClass,
    viewSectionClass,
    textareaReadOnly,
    textareaDisabled,
    selectDisabled,
  } = useFormFieldLock({
    formMode: toolbarMode,
    isStatusLocked: isFieldLocked,
    styles: df,
  });
  const ph = (text: string) => fieldPlaceholder(toolbarMode, text, { isStatusLocked: isFieldLocked });
  const searchFieldClass = [searchViewClass, df.embeddedSearch].filter(Boolean).join(' ');
  const lineAccountSearchClass = [searchViewClass, df.lineAccountSearch].filter(Boolean).join(' ');

  const currentSnapshot = useMemo(
    () => serializeJournalSnapshot({
      entryDate,
      code,
      description,
      referenceNo,
      referenceCustomerName,
      processingLevel: processingLevel || defaultProcessingLevel || '',
      entryType: showPktFields ? entryType : undefined,
      autoReverse: showPktFields ? autoReverse : undefined,
      lines,
    }),
    [entryDate, code, description, referenceNo, referenceCustomerName, processingLevel, defaultProcessingLevel, entryType, autoReverse, showPktFields, lines],
  );
  const isDirty = savedSnapshot !== null && currentSnapshot !== savedSnapshot;
  const {
    showUnsavedModal,
    guardedAction,
    confirmLeave,
    cancelLeave,
  } = useUnsavedChangesGuard(isDirty, isEditingMode(toolbarMode));

  const syncBannerFromFieldErrors = useCallback((fe: JournalEntryFieldErrors) => {
    setValidationErrors(collectJournalEntryBannerMessages(fe));
  }, []);

  const patchHeaderError = useCallback((key: 'entryDate' | 'processingLevel', error?: string) => {
    const msg = applyInlineValidationMessage(validationAttemptedRef.current, error);
    setFieldErrors(prev => {
      const next = { ...prev, [key]: msg };
      if (!msg) delete next[key];
      syncBannerFromFieldErrors(next);
      return next;
    });
  }, [syncBannerFromFieldErrors]);

  /** Init-data async — gỡ lỗi stale khi default mức XL về sau lần Lưu đầu. */
  useEffect(() => {
    if (!resolvedProcessingLevel.trim() || !fieldErrors.processingLevel) return;
    patchHeaderError('processingLevel', undefined);
  }, [resolvedProcessingLevel, fieldErrors.processingLevel, patchHeaderError]);

  const patchLineError = useCallback((
    idx: number,
    key: 'debitAccountCode' | 'creditAccountCode' | 'amount',
    error?: string,
  ) => {
    setFieldErrors(prev => {
      const linesMap = { ...(prev.lines ?? {}) };
      const row = { ...(linesMap[idx] ?? {}) };
      if (error) row[key] = error;
      else delete row[key];
      if (Object.keys(row).length === 0) delete linesMap[idx];
      else linesMap[idx] = row;
      const next: JournalEntryFieldErrors = { ...prev };
      if (Object.keys(linesMap).length === 0) delete next.lines;
      else next.lines = linesMap;
      syncBannerFromFieldErrors(next);
      return next;
    });
  }, [syncBannerFromFieldErrors]);

  const buildSnapshot = useCallback((): JournalEntrySnapshot => ({
    entryDate,
    code,
    description,
    referenceNo,
    referenceCustomerName,
    processingLevel: processingLevel || defaultProcessingLevel || '',
    lines,
  }), [entryDate, code, description, referenceNo, referenceCustomerName, processingLevel, defaultProcessingLevel, lines]);

  const applyJournalEntryDto = useCallback((v: JournalEntryDto, resetSaved: boolean, options?: { formMode?: FormMode }) => {
    const mappedLines = v.lines.length > 0
      ? v.lines.map(l => ({
        debitAccountCode: l.debitAccountCode,
        debitAccountName: l.debitAccountName ?? '',
        creditAccountCode: l.creditAccountCode,
        creditAccountName: l.creditAccountName ?? '',
        amount: l.amount,
        description: l.description ?? '',
      }))
      : [emptyLine()];
    setEntryDate(utcToLocalInputValue(v.entryDate).slice(0, 10));
    setCode(v.code);
    setDescription(v.description ?? '');
    setReferenceNo(v.referenceNo ?? '');
    setReferenceCustomerName('');
    if (v.referenceNo) {
      salesService.getContractByCode(v.referenceNo).then(c => {
        const name = c?.customerName ?? '';
        setReferenceCustomerName(name);
        if (resetSaved) {
          setSavedSnapshot(prev => {
            if (!prev) return prev;
            try {
              const snap = JSON.parse(prev) as JournalEntrySnapshot;
              return serializeJournalSnapshot({ ...snap, referenceCustomerName: name });
            } catch {
              return prev;
            }
          });
        }
      }).catch(() => {});
    }
    setStatus(v.status);
    setProcessingLevel(v.processingLevel || defaultProcessingLevel || '');
    setEntryType(v.entryType ?? 'Standard');
    setAutoReverse(v.autoReverse ?? false);
    setLines(mappedLines);
    const wantsEdit = options?.formMode !== undefined
      ? options.formMode === FormMode.Edit
      : shouldStartFormInEditMode(
        location.search,
        location.state as FormNavigateEditIntent | null,
      );
    setFormMode(wantsEdit ? FormMode.Edit : FormMode.View);
    if (resetSaved) {
      setSavedSnapshot(serializeJournalSnapshot({
        entryDate: utcToLocalInputValue(v.entryDate).slice(0, 10),
        code: v.code,
        description: v.description ?? '',
        referenceNo: v.referenceNo ?? '',
        referenceCustomerName: '',
        processingLevel: v.processingLevel || defaultProcessingLevel || '',
        entryType: v.entryType ?? 'Standard',
        autoReverse: v.autoReverse ?? false,
        lines: mappedLines,
      }));
    }
  }, [defaultProcessingLevel, location.search, location.state, setCode, setDescription, setEntryDate, setFormMode, setLines, setProcessingLevel, setReferenceCustomerName, setReferenceNo, setStatus]);

  const resetEmptyForm = useCallback(() => {
    const level = defaultProcessingLevel || '';
    setEntryDate(new Date().toISOString().slice(0, 10));
    setCode('');
    setDescription('');
    setReferenceNo('');
    setReferenceCustomerName('');
    setStatus('Draft');
    setProcessingLevel(level);
    setEntryType('Standard');
    setAutoReverse(false);
    setLines([emptyLine()]);
    validationAttemptedRef.current = false;
    setFieldErrors({});
    setValidationErrors([]);
    setSavedSnapshot(null);
    newFormBaselineReady.current = false;
  }, [defaultProcessingLevel, setCode, setDescription, setEntryDate, setLines, setProcessingLevel, setReferenceCustomerName, setReferenceNo, setStatus]);

  const applyCopySnapshot = useCallback((snap: JournalEntrySnapshot) => {
    setEntryDate(snap.entryDate || new Date().toISOString().slice(0, 10));
    setCode('');
    setDescription(snap.description);
    setReferenceNo(snap.referenceNo);
    setReferenceCustomerName('');
    setStatus('Draft');
    setProcessingLevel(snap.processingLevel || defaultProcessingLevel || '');
    setLines(snap.lines.length > 0 ? snap.lines : [emptyLine()]);
    setFormMode(FormMode.Create);
    setSavedSnapshot(serializeJournalSnapshot({
      ...snap,
      code: '',
      referenceCustomerName: snap.referenceCustomerName ?? '',
      processingLevel: snap.processingLevel || defaultProcessingLevel || '',
    }));
    newFormBaselineReady.current = true;
  }, [defaultProcessingLevel, setCode, setDescription, setEntryDate, setFormMode, setLines, setProcessingLevel, setReferenceCustomerName, setReferenceNo, setStatus]);

  const initNewSavedSnapshot = useCallback(() => {
    const level = processingLevel || defaultProcessingLevel || '';
    if (!level) return;
    if (!processingLevel) setProcessingLevel(level);
    if (!newFormBaselineReady.current) {
      setSavedSnapshot(serializeJournalSnapshot({
        entryDate: entryDate || new Date().toISOString().slice(0, 10),
        code,
        description,
        referenceNo,
        referenceCustomerName,
        processingLevel: level,
        lines,
      }));
      newFormBaselineReady.current = true;
    }
  }, [code, defaultProcessingLevel, description, entryDate, lines, processingLevel, referenceCustomerName, referenceNo, setProcessingLevel]);

  const closeOverlays = useCallback(() => {
    setShowSearchSlideout(false);
    setShowApproveModal(false);
    setShowPrintModal(false);
    setShowDeleteModal(false);
  }, []);

  const { copySourceVoucherCode } = useVoucherFormRoute<JournalEntrySnapshot>({
    isNew,
    id,
    location,
    navigate,
    setFormMode,
    setSearchResultIds,
    resetEmptyForm,
    applyCopySnapshot,
    initNewSavedSnapshot,
    onRouteChange: closeOverlays,
  });

  const fetchSearchList = useCallback(async (filter?: Parameters<typeof ktService.getJournalEntries>[0]) => {
    const res = await ktService.getJournalEntries({
      ...filter,
      entryKind: config.entryKind,
    });
    searchListItemsRef.current = res.items;
    for (const v of res.items) searchCacheRef.current.set(v.id, v);
    return {
      items: res.items.map(journalEntryToSearchRow),
      totalCount: res.totalCount,
    };
  }, [config.entryKind]);

  useEffect(() => {
    if (isNew) {
      const level = processingLevel || defaultProcessingLevel;
      if (!level) return;
      if (!processingLevel) setProcessingLevel(level);
      if (!newFormBaselineReady.current) {
        setSavedSnapshot(serializeJournalSnapshot({
          entryDate: entryDate || new Date().toISOString().slice(0, 10),
          code,
          description,
          referenceNo,
          referenceCustomerName,
          processingLevel: level,
          lines,
        }));
        newFormBaselineReady.current = true;
      }
      return;
    }
    newFormBaselineReady.current = false;
    let cancelled = false;
    const cached = id ? searchCacheRef.current.get(id) : undefined;
    if (cached) {
      applyJournalEntryDto(cached, true);
      setLoading(false);
      return () => { cancelled = true; };
    }
    setLoading(true);
    const t = setTimeout(() => {
      ktService.getJournalEntry(id!)
        .then(v => {
          if (cancelled) return;
          searchCacheRef.current.set(id!, v);
          if (searchCacheRef.current.size > VOUCHER_SEARCH_CACHE_MAX) {
            const keep = new Set(searchResultIds);
            for (const key of [...searchCacheRef.current.keys()]) {
              if (!keep.has(key)) searchCacheRef.current.delete(key);
            }
          }
          applyJournalEntryDto(v, true);
        })
        .catch(err => { if (!cancelled) dispatchAppToast(dispatch, { message: getApiErrorMessage(err, 'Lỗi tải'), type: 'error' }); })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [id, dispatch, isNew, defaultProcessingLevel, applyJournalEntryDto, searchResultIds]);

  const applyPostedJournalEntry = useCallback(async (entryId: string) => {
    const v = await ktService.getJournalEntry(entryId);
    applyJournalEntryDto(v, true, { formMode: FormMode.View });
    setPostingStatus('Posted');
  }, [applyJournalEntryDto]);

  const refreshPostingStatusAfterAutoPost = useCallback(async (level: string, entryId?: string) => {
    if (level !== '9' || !entryId) return;
    try {
      const ps = await ktService.getJournalEntryPostingStatus(entryId);
      setPostingStatus(ps.postingStatus);
      if (ps.postingStatus === 'Queued' || ps.postingStatus === 'Processing') {
        const final = await pollDocumentPostingStatus(() => ktService.getJournalEntryPostingStatus(entryId));
        setPostingStatus(final.postingStatus);
        if (final.postingStatus === 'Failed') {
          dispatchAppToast(dispatch, {
            message: final.lastError ?? 'Ghi sổ thất bại.',
            type: 'error',
          });
          return;
        }
        if (final.postingStatus === 'Posted') {
          await applyPostedJournalEntry(entryId);
          dispatchAppToast(dispatch, { message: 'Ghi sổ thành công', type: 'success' });
        }
      } else if (ps.postingStatus === 'Posted') {
        await applyPostedJournalEntry(entryId);
      }
    } catch {
      /* optional — không chặn form */
    }
  }, [applyPostedJournalEntry, dispatch]);

  useEffect(() => {
    if (isNew || !id) {
      setPostingStatus('None');
      return;
    }
    let cancelled = false;
    const t = setTimeout(() => {
      void (async () => {
        try {
          const ps = await ktService.getJournalEntryPostingStatus(id);
          if (cancelled) return;
          setPostingStatus(ps.postingStatus);
          if (ps.postingStatus !== 'Queued' && ps.postingStatus !== 'Processing') return;

          const final = await pollDocumentPostingStatus(() => ktService.getJournalEntryPostingStatus(id));
          if (cancelled) return;
          setPostingStatus(final.postingStatus);
          if (final.postingStatus === 'Posted') {
            await applyPostedJournalEntry(id);
          } else if (final.postingStatus === 'Failed' && final.lastError) {
            dispatchAppToast(dispatch, { message: final.lastError, type: 'error' });
          }
        } catch {
          /* optional */
        }
      })();
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [id, isNew, dispatch, applyPostedJournalEntry]);

  const totalDebit = lines.reduce((s, l) => s + (Number(l.amount) || 0), 0);

  const buildPayload = (): CreateJournalEntryDto => ({
    entryDate: localInputToISOWithOffset(entryDate),
    description: description || undefined,
    referenceNo: showContractRef ? (referenceNo || undefined) : undefined,
    entryKind: config.entryKind,
    entryType: showPktFields ? entryType : undefined,
    autoReverse: showPktFields ? autoReverse : false,
    processingLevel: processingLevel || defaultProcessingLevel || '',
    lines: lines.map(l => ({
      debitAccountCode: l.debitAccountCode,
      creditAccountCode: l.creditAccountCode,
      amount: Number(l.amount),
      description: l.description || undefined,
    })),
  });

  const runValidate = (): boolean => {
    const resolvedProcessingLevel = processingLevel || defaultProcessingLevel || '';
    if (!processingLevel && resolvedProcessingLevel) {
      setProcessingLevel(resolvedProcessingLevel);
    }
    const { fieldErrors: nextFieldErrors, bannerMessages } = validateJournalEntryFields({
      entryDate,
      processingLevel: resolvedProcessingLevel,
      lines,
    });
    const periodError = validateVoucherDateAgainstPeriods(entryDate, accountingPeriods);
    if (periodError) {
      nextFieldErrors.entryDate = periodError;
      bannerMessages.push(periodError);
    }
    if (bannerMessages.length > 0) {
      setFieldErrors(nextFieldErrors);
      setValidationErrors(bannerMessages);
      setBannerClosed(false);
      setBannerExpanded(true);
      scrollToFirstJournalEntryFieldError(nextFieldErrors, tid, validationBannerId);
      return false;
    }
    setFieldErrors({});
    setValidationErrors([]);
    return true;
  };

  const handleSave = async () => {
    validationAttemptedRef.current = true;
    if (!runValidate()) return;
    setSaving(true);
    try {
      const payload = buildPayload();
      const resolvedLevel = processingLevel || defaultProcessingLevel || '';
      if (isNew) {
        const created = await ktService.createJournalEntry(payload);
        setCode(created.code ?? '');
        dispatchAppToast(dispatch, { message: 'Tạo bút toán thành công', type: 'success' });
        navigate(config.detailPath(created.id));
      } else {
        const updated = await ktService.updateJournalEntry(id!, payload);
        applyJournalEntryDto(updated, true, { formMode: FormMode.View });
        dispatchAppToast(dispatch, { message: 'Cập nhật thành công', type: 'success' });
        syncEditModeInUrl(FormMode.View);
        void refreshPostingStatusAfterAutoPost(updated.processingLevel ?? resolvedLevel, id!);
      }
    } catch (e: unknown) {
      dispatchAppToast(dispatch, { message: getApiErrorMessage(e, 'Lỗi lưu'), type: 'error' });
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async () => {
    if (isNew) return;
    try {
      await ktService.deleteJournalEntry(id!);
      dispatchAppToast(dispatch, { message: 'Xóa thành công', type: 'success' });
      navigate(config.listPath);
    } catch (e: unknown) {
      dispatchAppToast(dispatch, { message: getApiErrorMessage(e, 'Lỗi xóa'), type: 'error' });
    } finally {
      setShowDeleteModal(false);
    }
  };

  const handleAddLine = () => {
    const afterIdx = selectedLineIndex >= 0 && selectedLineIndex < lines.length
      ? selectedLineIndex
      : lines.length - 1;
    const insertAt = afterIdx + 1;
    insertLineAfter(afterIdx);
    setFieldErrors(prev => ({
      ...prev,
      lines: insertJournalEntryLineFieldErrors(prev.lines, insertAt),
    }));
    setSelectedLineIndex(insertAt);
  };

  const handleCopyLine = () => {
    if (lines.length === 0) return;
    const afterIdx = selectedLineIndex >= 0 && selectedLineIndex < lines.length
      ? selectedLineIndex
      : lines.length - 1;
    const source = lines[afterIdx];
    const insertAt = afterIdx + 1;
    insertLineAfter(afterIdx, { ...source });
    setFieldErrors(prev => ({
      ...prev,
      lines: insertJournalEntryLineFieldErrors(prev.lines, insertAt),
    }));
    setSelectedLineIndex(insertAt);
  };

  const handleSelectLine = (idx: number) => setSelectedLineIndex(idx);

  const handleRemoveLine = (idx: number) => {
    if (lines.length <= 1) {
      dispatchAppToast(dispatch, { message: 'Phải có ít nhất 1 dòng định khoản', type: 'warning' });
      return;
    }
    removeLine(idx);
    setFieldErrors(prev => ({
      ...prev,
      lines: shiftJournalEntryLineFieldErrors(prev.lines, idx),
    }));
    setSelectedLineIndex(i => (i > idx ? i - 1 : Math.min(i, lines.length - 2)));
  };
  const handleUpdateLine = (idx: number, patch: Partial<LineRow>) => {
    updateLine(idx, patch);
    if (patch.debitAccountCode !== undefined) patchLineError(idx, 'debitAccountCode', undefined);
    if (patch.creditAccountCode !== undefined) patchLineError(idx, 'creditAccountCode', undefined);
    if (patch.amount !== undefined) patchLineError(idx, 'amount', undefined);
  };

  const handleBack = () => guardedAction(() => {
    setSearchResultIds([]);
    navigate(config.listPath);
  });
  /** Journal entry ERP: Phê duyệt mức xử lý — không nút Ghi sổ toolbar (`voucher-form-toolbar.md` §8.10). */
  const showPostButton = false;
  const toolbarFlags = useMemo(
    () => resolveVoucherFormToolbarFlags({
      formPermissions,
      isNew,
      status,
      processingLevel,
      voucherDate: entryDate,
      id,
      postingStatus,
      accountingPeriods,
    }),
    [formPermissions, isNew, status, processingLevel, entryDate, id, postingStatus, accountingPeriods],
  );
  const toolbarDisabledReasons = useMemo(
    () => ({
      ...buildVoucherToolbarDisabledReasons({ isNew, status, showPostButton, isStatusLocked: isViewReadOnly }),
      approve: voucherApproveDisabledReason({
        isNew,
        status,
        processingLevel,
        voucherDate: entryDate,
        periods: accountingPeriods,
      }),
      save: !toolbarFlags.canSaveToolbar ? 'Không có quyền lưu chứng từ' : undefined,
    }),
    [isNew, status, isViewReadOnly, processingLevel, entryDate, accountingPeriods, toolbarFlags.canSaveToolbar],
  );
  const processingLevelLabel = formatProcessingLevelFromOptions(processingLevel, processingOpts);

  const searchNavIndex = id ? searchResultIds.indexOf(id) : -1;
  const hasSearchNav = searchNavIndex >= 0 && searchResultIds.length > 0;

  const navigateToSearchId = (targetId: string) => {
    guardedAction(() => navigate(
      config.detailPath(targetId),
      { state: buildVoucherSearchNavigateState(searchResultIds) },
    ));
  };

  const handleCopy = () => {
    guardedAction(() => {
      navigate(config.createPath, { state: buildVoucherCopyNavigateState(buildSnapshot(), code) });
    });
  };

  const handleOpenFromSearch = (voucherId: string, resultIds: string[], items: CashVoucherDto[]) => {
    for (const v of searchListItemsRef.current) {
      if (items.some(r => r.id === v.id)) searchCacheRef.current.set(v.id, v);
    }
    setSearchResultIds(resultIds);
    setShowSearchSlideout(false);
    guardedAction(() => navigate(
      config.detailPath(voucherId),
      { state: buildVoucherSearchNavigateState(resultIds, items) },
    ));
  };

  const handlePrintConfirm = async (templateId: string) => {
    setPrinting(true);
    try {
      dispatchAppToast(dispatch, {
        message: `In PDF (placeholder) — mẫu: ${templateId}. Triển khai preview/PDF sau.`,
        type: 'info',
      });
      setShowPrintModal(false);
    } finally {
      setPrinting(false);
    }
  };

  const revertToSaved = useCallback(() => {
    if (!savedSnapshot) return;
    try {
      const snap = JSON.parse(savedSnapshot) as JournalEntrySnapshot;
      applyFormState({
        entryDate: snap.entryDate,
        code: snap.code ?? code,
        description: snap.description,
        referenceNo: snap.referenceNo,
        referenceCustomerName: snap.referenceCustomerName ?? '',
        processingLevel: snap.processingLevel,
      }, snap.lines.length > 0 ? snap.lines : [emptyLine()], status);
      validationAttemptedRef.current = false;
      setFieldErrors({});
      setValidationErrors([]);
      setBannerClosed(false);
      setSelectedLineIndex(0);
    } catch {
      /* ignore corrupt snapshot */
    }
  }, [savedSnapshot, applyFormState, code, status]);

  const handleCancel = () => {
    if (isNew) {
      guardedAction(() => navigate(config.listPath));
      return;
    }
    if (formMode === FormMode.Edit) {
      revertToSaved();
      setFormMode(FormMode.View);
      syncEditModeInUrl(FormMode.View);
      return;
    }
    navigate(config.listPath);
  };

  const handleApproveConfirm = async (newLevel: string) => {
    setApproving(true);
    try {
      if (!isNew && id) {
        const updated = await ktService.updateJournalEntry(id, { ...buildPayload(), processingLevel: newLevel });
        applyJournalEntryDto(updated, true);
        dispatchAppToast(dispatch, { message: 'Đã cập nhật mức xử lý', type: 'success' });
        void refreshPostingStatusAfterAutoPost(newLevel, id);
      } else {
        setProcessingLevel(newLevel);
        setSavedSnapshot(serializeJournalSnapshot({
          entryDate,
          code,
          description,
          referenceNo,
          referenceCustomerName,
          processingLevel: newLevel,
          lines,
        }));
        dispatchAppToast(dispatch, {
          message: 'Đã cập nhật mức xử lý (lưu cùng chứng từ khi ghi nhận)',
          type: 'success',
        });
      }
      setShowApproveModal(false);
    } catch (e: unknown) {
      dispatchAppToast(dispatch, {
        message: getApiErrorMessage(e, 'Cập nhật mức xử lý thất bại. Vui lòng thử lại.'),
        type: 'error',
      });
    } finally {
      setApproving(false);
    }
  };

  if (initError) return (
    <div className={df.pageVoucher} data-testid={tid('init-error')}>
      <div className={df.formErrorMessage}>
        <p className={df.formErrorTitle}>Không thể tải dữ liệu form</p>
        <p className={df.formErrorDetail}>{initError}</p>
      </div>
    </div>
  );

  if (initLoading || loading) return (
    <div className={df.formInitLoading} data-testid={tid('form-init-loading')}>
      <div className={df.formInitSpinner} />
      <p>Đang tải...</p>
    </div>
  );

  const focusLineRow = (idx: number) => {
    rowRefs.current[idx]?.focus({ preventScroll: true });
  };

  return (
    <div
      ref={shellRef}
      className={[df.pageVoucher, embedSlideout ? df.pageVoucherSlideoutEmbed : ''].filter(Boolean).join(' ')}
      data-voucher-form-shell
      data-form-embed-slideout={embedSlideout || undefined}
      data-testid={tid('form')}
    >
      {!embedSlideout && (
      <div className={df.pageFormHeader}>
        <div className={df.stickyTop}>
          <VoucherFormToolbar
            testIdPrefix={config.testIdPrefix}
            title={isNew ? config.formTitleNew : config.formTitleEdit(code)}
            processingLevelBadge={
              !isNew ? <VoucherFormStatusGroup processingLevelLabel={processingLevelLabel} /> : undefined
            }
            formMode={toolbarMode}
            viewModeHint={resolveVoucherViewModeHint({
              formMode: toolbarMode,
              isNew,
              status,
              processingLevel,
              canEditWhenView: toolbarFlags.canEditToolbar,
            })}
            copySourceVoucherCode={copySourceVoucherCode}
            canApprove={toolbarFlags.canApproveToolbar}
            showApproveButton={toolbarFlags.showApproveToolbar}
            showPostButton={showPostButton}
            canPost={false}
            canCopy={toolbarFlags.canCopyToolbar}
            canPrint={toolbarFlags.canPrintToolbar}
            canEdit={toolbarFlags.canEditToolbar}
            showEditButton={toolbarFlags.showEditButton}
            canDelete={toolbarFlags.canDeleteToolbar}
            showDeleteButton={toolbarFlags.showDeleteButton}
            showNewButton={toolbarFlags.showNewButton}
            canSave={toolbarFlags.canSaveToolbar}
            disabledReasons={toolbarDisabledReasons}
            saving={saving}
            saveLabel={isNew ? 'Tạo mới' : 'Lưu thay đổi'}
            searchNav={hasSearchNav ? {
              index: searchNavIndex,
              total: searchResultIds.length,
              onFirst: () => navigateToSearchId(searchResultIds[0]),
              onPrev: () => navigateToSearchId(searchResultIds[searchNavIndex - 1]),
              onNext: () => navigateToSearchId(searchResultIds[searchNavIndex + 1]),
              onEnd: () => navigateToSearchId(searchResultIds[searchResultIds.length - 1]),
            } : undefined}
            onBack={handleBack}
            onApprove={() => setShowApproveModal(true)}
            onPost={() => {}}
            canViewLedger={toolbarFlags.canViewLedgerToolbar}
            onViewLedger={() => setShowLedgerModal(true)}
            onCopy={handleCopy}
            onPrint={() => setShowPrintModal(true)}
            onSearch={() => setShowSearchSlideout(true)}
            onNew={() => navigate(config.createPath)}
            onEdit={() => {
              setFormMode(FormMode.Edit);
              syncEditModeInUrl(FormMode.Edit);
            }}
            onSave={handleSave}
            onCancel={handleCancel}
            onDelete={() => setShowDeleteModal(true)}
            insetShell
          />
          {(postingStatus === 'Queued' || postingStatus === 'Processing') && (
            <div className={df.readOnlyHint} data-testid={tid('posting-status-hint')}>
              <i className="fas fa-spinner fa-spin" />{' '}
              {postingStatus === 'Processing' ? 'Đang ghi sổ…' : 'Đang chờ ghi sổ…'}
            </div>
          )}
        </div>
      </div>
      )}

      <div ref={scrollRef} className={df.pageFormScroll} data-testid={tid('form-scroll')}>
        <ValidationErrorBanner
          errors={validationErrors}
          closed={bannerClosed}
          expanded={bannerExpanded}
          onToggle={() => setBannerExpanded(v => !v)}
          onClose={() => setBannerClosed(true)}
          bannerId={validationBannerId}
        />

        <div className={`${df.section} ${viewSectionClass ?? ''}`} data-testid={tid('section-header')}>
          <h2 className={df.sectionTitle}>Thông tin chứng từ</h2>
          <div className={df.row4}>
            <div className={df.field} data-testid={tid('field-entryDate')} id={tid('field-entryDate')}>
              <label className={df.label}>Ngày bút toán *</label>
              <Input
                type="date"
                value={entryDate}
                onChange={e => {
                  setEntryDate(e.target.value);
                  patchHeaderError('entryDate', undefined);
                }}
                error={fieldErrors.entryDate}
                {...fieldLockProps}
              />
            </div>
            <div className={df.field} data-testid={tid('field-code')}>
              <label className={df.label}>Số chứng từ</label>
              <Input
                value={code}
                placeholder={ph('Tự động sinh')}
                {...staticFieldProps}
              />
            </div>
            {showContractRef ? (
              <div className={df.field} data-testid={tid('field-referenceNo')} id={tid('field-referenceNo')}>
                <label className={df.label}>Số tham chiếu (HĐ)</label>
                <ContractSearchField
                  contractCode={referenceNo}
                  customerName={referenceCustomerName}
                  onSelect={(c, name) => { setReferenceNo(c); setReferenceCustomerName(name); }}
                  onClear={() => { setReferenceNo(''); setReferenceCustomerName(''); }}
                  disabled={searchDisabled}
                  className={searchFieldClass}
                />
              </div>
            ) : (
              <div className={df.field} aria-hidden />
            )}
            <div className={df.field} aria-hidden />
          </div>
          <div className={df.row4}>
            <div className={`${df.field} ${descriptionSpanClass}`} data-testid={tid('field-description')}>
              <label className={df.label}>Diễn giải</label>
              <VoucherDescriptionField
                value={description}
                onChange={v => setDescription(v)}
                readOnly={textareaReadOnly}
                disabled={textareaDisabled}
              />
            </div>
            {showContractRef && <div className={df.field} aria-hidden />}
          </div>
          {showPktFields && (
            <div className={df.row4}>
              <div className={df.field} data-testid={tid('field-entryType')}>
                <label className={df.label}>Loại bút toán</label>
                <Select
                  options={journalEntryTypeOptions}
                  value={entryType}
                  onChange={(e: React.ChangeEvent<HTMLSelectElement>) => setEntryType(e.target.value)}
                  disabled={fieldLockProps.disabled}
                />
              </div>
              <div className={df.field} data-testid={tid('field-autoReverse')}>
                <Checkbox
                  label="Thoái bút đầu kỳ sau"
                  checked={autoReverse}
                  onChange={e => setAutoReverse(e.target.checked)}
                  disabled={fieldLockProps.disabled}
                  data-testid={tid('field-autoReverse-cb')}
                />
              </div>
              <div className={df.field} aria-hidden />
              <div className={df.field} aria-hidden />
            </div>
          )}
        </div>

        <div
          ref={linesSectionRef}
          className={`${df.section} ${viewSectionClass ?? ''}`}
          data-testid={tid('section-lines')}
        >
          <h2 className={df.sectionTitle}>Chi tiết định khoản</h2>
          <div className={df.tableWrapper}>
            <table className={[df.linesTable, df.linesTableStacked].join(' ')}>
              <colgroup>
                <col className={df.linesColJeDebit} />
                <col className={df.linesColJeCredit} />
                <col className={df.linesColJeAmount} />
                <col className={df.linesColJeDesc} />
                {isEditingMode(toolbarMode) && !isFieldLocked && <col className={df.linesColDel} />}
              </colgroup>
              <thead>
                <tr>
                  <th className={df.thAccount}>TK Nợ</th>
                  <th className={df.thAccount}>TK Có</th>
                  <th className={df.thAmount}>Số tiền</th>
                  <th className={df.thDesc}>Diễn giải dòng</th>
                  {isEditingMode(toolbarMode) && !isFieldLocked && <th className={df.thDel} />}
                </tr>
              </thead>
              <tbody>
                {lineRows.map((lineState, idx) => {
                  const line = lines[idx];
                  const isSelected = selectedLineIndex === idx;
                  const rowClass = isSelected ? df.lineRowSelected : '';
                  return (
                    <tr
                      key={lineState.lineId}
                      ref={el => { rowRefs.current[idx] = el; }}
                      className={[df.lineRow, rowClass].filter(Boolean).join(' ')}
                      data-testid={tid(`line-${idx}`)}
                      tabIndex={isSelected ? 0 : -1}
                      aria-selected={isSelected}
                      onClick={e => {
                        handleSelectLine(idx);
                        const target = e.target as HTMLElement;
                        if (isLineRowFieldTarget(target)) return;
                        focusLineRow(idx);
                      }}
                      onKeyDown={e => {
                        if (e.key !== 'ArrowUp' && e.key !== 'ArrowDown') return;
                        const target = e.target as HTMLElement;
                        if (isLineRowFieldTarget(target)) return;
                        e.preventDefault();
                        if (e.key === 'ArrowDown' && idx < lines.length - 1) {
                          handleSelectLine(idx + 1);
                        } else if (e.key === 'ArrowUp' && idx > 0) {
                          handleSelectLine(idx - 1);
                        }
                      }}
                    >
                      <td id={tid(`line-${idx + 1}-debit`)} data-label="TK Nợ">
                        <AccountSearchInput
                          api={erpFinanceAccountSearchApi}
                          configOptions={accountSearchOptions}
                          className={lineAccountSearchClass}
                          value={line.debitAccountCode}
                          primaryDisplay={formatAccountDisplay(line.debitAccountCode, line.debitAccountName)}
                          onChange={a => handleUpdateLine(idx, { debitAccountCode: a.code, debitAccountName: a.name })}
                          onClear={() => handleUpdateLine(idx, { debitAccountCode: '', debitAccountName: '' })}
                          showLabel={false}
                          showSecondaryInput={false}
                          placeholder={ph('TK Nợ...')}
                          disabled={searchDisabled}
                          error={fieldErrors.lines?.[idx]?.debitAccountCode}
                          data-testid={tid(`line-${idx + 1}-debit`)}
                        />
                      </td>
                      <td id={tid(`line-${idx + 1}-credit`)} data-label="TK Có">
                        <AccountSearchInput
                          api={erpFinanceAccountSearchApi}
                          configOptions={accountSearchOptions}
                          className={lineAccountSearchClass}
                          value={line.creditAccountCode}
                          primaryDisplay={formatAccountDisplay(line.creditAccountCode, line.creditAccountName)}
                          onChange={a => handleUpdateLine(idx, { creditAccountCode: a.code, creditAccountName: a.name })}
                          onClear={() => handleUpdateLine(idx, { creditAccountCode: '', creditAccountName: '' })}
                          showLabel={false}
                          showSecondaryInput={false}
                          placeholder={ph('TK Có...')}
                          disabled={searchDisabled}
                          error={fieldErrors.lines?.[idx]?.creditAccountCode}
                          data-testid={tid(`line-${idx + 1}-credit`)}
                        />
                      </td>
                      <td data-testid={tid(`line-${idx + 1}-amount`)} id={tid(`line-${idx + 1}-amount`)} data-label="Số tiền">
                        <MoneyInput
                          value={line.amount}
                          onChange={amount => handleUpdateLine(idx, { amount })}
                          disabled={fieldLockProps.disabled}
                          readOnly={fieldLockProps.readOnly}
                          error={fieldErrors.lines?.[idx]?.amount}
                        />
                      </td>
                      <td data-label="Diễn giải dòng">
                        <Input
                          value={line.description}
                          onChange={e => handleUpdateLine(idx, { description: e.target.value })}
                          placeholder={ph('Nội dung...')}
                          {...fieldLockProps}
                        />
                      </td>
                      {isEditingMode(toolbarMode) && !isFieldLocked && (
                        <td className={df.tdDel}>
                          <button
                            type="button"
                            className={df.btnDeleteLine}
                            onClick={e => {
                              e.stopPropagation();
                              handleRemoveLine(idx);
                            }}
                            title="Xóa dòng"
                            data-testid={tid(`line-${idx + 1}-delete`)}
                          >
                            <i className="fas fa-trash-alt" aria-hidden="true" />
                          </button>
                        </td>
                      )}
                    </tr>
                  );
                })}
              </tbody>
            </table>
          </div>
          {isEditingMode(toolbarMode) && !isFieldLocked && (
            <div className={df.linesActions}>
              <button type="button" className={df.btnAddLine} data-testid={tid('add-line-btn')} onClick={handleAddLine}>
                + Thêm định khoản
              </button>
              <button
                type="button"
                className={df.btnCopyLine}
                data-testid={tid('copy-line-btn')}
                onClick={handleCopyLine}
                disabled={lines.length === 0}
              >
                Sao chép dòng
              </button>
            </div>
          )}
        </div>
      </div>

      <div className={df.pageFormFooter} data-testid={tid('form-footer')}>
        <div className={[df.footer, viewSectionClass].filter(Boolean).join(' ')}>
          <div className={df.footerLeft} id={tid('field-processingLevel')} data-testid={tid('field-processingLevel')}>
            <label className={df.label}>Mức xử lý</label>
            <Select
              options={processingOpts}
              value={resolvedProcessingLevel}
              error={fieldErrors.processingLevel}
              onChange={e => {
                const v = e.target.value;
                setProcessingLevel(v);
                patchHeaderError('processingLevel', v ? undefined : 'Mức xử lý là bắt buộc');
              }}
              disabled={selectDisabled}
            />
          </div>
          <div className={df.totalBlock}>
            <LabelMoney
              label="Tổng Nợ/Có:"
              value={totalDebit}
              variant="footer"
              emphasize
              data-testid={tid('footer-totalDebit')}
            />
          </div>
        </div>
      </div>

      <VoucherSearchSlideout
        isOpen={showSearchSlideout}
        onClose={() => setShowSearchSlideout(false)}
        title={`Tìm ${config.listTitle.toLowerCase()}`}
        testIdPrefix={config.testIdPrefix}
        listScope={config.searchListScope}
        fetchList={fetchSearchList}
        onOpenVoucher={handleOpenFromSearch}
        processingLevelFilterOptions={processingOpts}
        formatProcessingLevel={level => formatProcessingLevelFromOptions(level, processingOpts)}
      />

      <VoucherPrintModal
        isOpen={showPrintModal}
        onClose={() => setShowPrintModal(false)}
        voucherTitle={!isNew ? `${config.listTitle} — ${code || '...'}` : undefined}
        onPrint={handlePrintConfirm}
        printing={printing}
        testIdPrefix={config.testIdPrefix}
      />

      {!isNew && id && (
        <VoucherPostedLedgerModal
          isOpen={showLedgerModal}
          onClose={() => setShowLedgerModal(false)}
          voucherTitle={`${config.listTitle} — ${code || '...'}`}
          testIdPrefix={config.testIdPrefix}
          fetchPostedLedger={() => ktService.getJournalEntryPostedLedger(id)}
          fetchPostingStatus={() => ktService.getJournalEntryPostingStatus(id)}
        />
      )}

      <Modal isOpen={showDeleteModal} onClose={() => setShowDeleteModal(false)} title="Xác nhận xóa">
        <p>Bạn có chắc muốn xóa bút toán này?</p>
        <div className={df.modalActions}>
          <Button variant="secondary" onClick={() => setShowDeleteModal(false)}>Hủy</Button>
          <Button variant="danger" data-testid={tid('delete-confirm-btn')} onClick={handleDelete}>Xóa</Button>
        </div>
      </Modal>

      <ProcessingLevelApproveModal
        isOpen={showApproveModal}
        onClose={() => setShowApproveModal(false)}
        currentLevel={processingLevel}
        levelOptions={processingOpts}
        onConfirm={handleApproveConfirm}
        saving={approving}
        testIdPrefix={config.testIdPrefix}
      />

      <UnsavedChangesModal
        isOpen={showUnsavedModal}
        onStay={cancelLeave}
        onLeave={confirmLeave}
        data-testid={tid('unsaved-modal')}
      />
    </div>
  );
};
